function parseFileSize(raw) {
  if (typeof raw === 'number' && Number.isFinite(raw)) return raw;
  const txt = String(raw || '').trim().toLowerCase();
  if (!txt) return 0;

  const numeric = Number.parseFloat(txt.replace(',', '.'));
  if (!Number.isFinite(numeric)) return 0;

  if (txt.endsWith('kb')) return Math.round(numeric * 1024);
  if (txt.endsWith('mb')) return Math.round(numeric * 1024 * 1024);
  if (txt.endsWith('gb')) return Math.round(numeric * 1024 * 1024 * 1024);
  return Math.round(numeric);
}

