def _normalized_target(value: Any) -> Optional[str]:
    if not isinstance(value, str):
        return None
    target = value.strip()
    if not target or target.lower() in {"none", "null", "n/a", "na"}:
        return None
    return target


def _normalize_dropdown_option(value: Any) -> Optional[str]:
    if isinstance(value, str):
        text = value.strip()
        return text if text else None
    if isinstance(value, dict):
        raw = value.get("txt", value.get("label", value.get("value")))
        if isinstance(raw, str):
            text = raw.strip()
            return text if text else None
    return None


def _extract_dropdown_options(value: Any) -> List[str]:
    if not isinstance(value, list):
        return []
    options: List[str] = []
    for item in value:
        option = _normalize_dropdown_option(item)
        if option:
            options.append(option)
    return options


