      requirementsText,
      'API',
      openapiText,
      'PLAN',
      compactJson(allPlannedPaths),
      'BATCH',
      compactJson(batchPaths),
      'STATE',
      compactJson({
        i: json.iteration,
        g: json.generatedFileCountTotal,
        r: json.remainingFileCount,
        t: allPlannedPaths.length,
        b: batchSize,
        c: currentBatchFiles.length,
