        const name = parameter.required ? parameter.name : parameter.name + '?';
        if (!output[location]) output[location] = {};
        const summary = parameter.schema ? this.compactSchema(parameter.schema) : 'any';

        if (this.includeDescriptions && parameter.description) {
          output[location][name] = {
            t: summary,
            d: this.cleanText(parameter.description),
          };
        } else {
          output[location][name] = summary;
        }
      }

      return output;
    }

    compactRequestBody(requestBody) {
      if (!requestBody) return null;

      const resolved = this.resolveIfRef(requestBody) || {};
      const output = {};
      if (resolved.required) output.req = true;

      const content = this.compactContent(resolved.content || {});
      if (Object.keys(content).length) output.content = content;

      if (this.includeDescriptions && resolved.description) {
        output.d = this.cleanText(resolved.description);
      }

      return Object.keys(output).length ? output : null;
    }

    compactResponses(responses) {
      const output = {};

      for (const [statusCode, response] of Object.entries(responses || {})) {
        const resolved = this.resolveIfRef(response) || {};
        const item = {};

        const content = this.compactContent(resolved.content || {});
        if (Object.keys(content).length) item.content = content;

        const headers = this.compactHeaders(resolved.headers || {});
        if (Object.keys(headers).length) item.headers = headers;

        output[String(statusCode)] = Object.keys(item).length ? item : 'response';
      }

      return output;
    }

    compactHeaders(headers) {
      const output = {};
      for (const [name, header] of Object.entries(headers || {})) {
        const resolved = this.resolveIfRef(header) || {};
        output[name] = resolved.schema ? this.compactSchema(resolved.schema) : 'any';
      }
      return output;
    }

    compactContent(content) {
      const output = {};
      for (const [contentType, mediaType] of Object.entries(content || {})) {
        const resolved = this.resolveIfRef(mediaType) || {};
        let entry = resolved.schema ? this.compactSchema(resolved.schema) : 'any';

        if (this.includeDescriptions) {
          if (resolved.example !== undefined) {
            entry = { schema: entry, example: resolved.example };
          } else if (resolved.examples) {
            entry = { schema: entry, examples: Object.keys(resolved.examples).sort() };
          }
        }

        output[contentType] = entry;
      }
      return output;
    }

    compactComponentSchemas() {
      const schemas = (((this.spec || {}).components || {}).schemas) || {};
      const output = {};
      const queue = Array.from(this.referencedSchemaNames);
      const visited = new Set();

      while (queue.length) {
        const name = queue.shift();
        if (!name || visited.has(name) || !schemas[name]) continue;
        visited.add(name);
        output[name] = this.compactSchema(schemas[name], name);

        for (const referencedName of this.referencedSchemaNames) {
          if (!visited.has(referencedName) && !queue.includes(referencedName)) {
            queue.push(referencedName);
          }
        }
      }

      return output;
    }

    compactSchema(schema, name = null) {
      if (schema === undefined || schema === null) return 'any';

      if (schema && typeof schema === 'object' && schema.$ref) {
        return this.refLabel(schema.$ref);
      }

      const resolved = this.resolveIfRef(schema);
      if (!resolved || typeof resolved !== 'object') return 'any';

      if (name && this.schemaCache.has(name)) {
        return this.schemaCache.get(name);
      }

      let result;
      if (Array.isArray(resolved.allOf)) {
        result = { allOf: resolved.allOf.map((item) => this.compactSchema(item)) };
      } else if (Array.isArray(resolved.oneOf)) {
        result = { oneOf: resolved.oneOf.map((item) => this.compactSchema(item)) };
      } else if (Array.isArray(resolved.anyOf)) {
        result = { anyOf: resolved.anyOf.map((item) => this.compactSchema(item)) };
      } else if (resolved.type === 'array' || resolved.items) {
        result = [this.compactSchema(resolved.items)];
      } else if (this.looksLikeObjectSchema(resolved)) {
        result = this.compactObjectSchema(resolved);
      } else {
        result = this.compactScalarSchema(resolved);
      }

      result = this.applyNullable(result, resolved);
      if (name) this.schemaCache.set(name, result);
      return result;
    }

    compactObjectSchema(schema) {
      const properties = schema.properties || {};
      const required = new Set(Array.isArray(schema.required) ? schema.required : []);
      const output = {};

      for (const [propertyName, propertySchema] of Object.entries(properties)) {
        const key = required.has(propertyName) ? propertyName : propertyName + '?';
        output[key] = this.compactSchema(propertySchema);
      }

      if (schema.additionalProperties) {
        output['*'] = schema.additionalProperties === true
          ? 'any'
          : this.compactSchema(schema.additionalProperties);
      }

      if (!Object.keys(output).length) {
        return 'object';
      }

      if (this.includeDescriptions && schema.description) {
        return {
          type: output,
          d: this.cleanText(schema.description),
        };
      }

      return output;
    }

    compactScalarSchema(schema) {
      let value = schema.type || 'any';
      if (schema.format) value += ':' + schema.format;
      if (Array.isArray(schema.enum) && schema.enum.length) {
        value += '[' + schema.enum.map((item) => JSON.stringify(item)).join(',') + ']';
      }
      return value;
    }

    applyNullable(result, schema) {
      if (!schema.nullable) return result;
      if (typeof result === 'string') return result + '|null';
      return { nullable: result };
    }

    looksLikeObjectSchema(schema) {
      return schema.type === 'object' || schema.properties || schema.additionalProperties;
    }

    resolveIfRef(node) {
      if (!node || typeof node !== 'object') return node;
      if (!node.$ref) return node;

      const ref = node.$ref;
      if (this.resolvedRefs.has(ref)) {
        return this.resolvedRefs.get(ref);
      }

      let target = this.spec;
      for (const rawPart of String(ref).replace(/^#\//, '').split('/')) {
        const part = rawPart.replace(/~1/g, '/').replace(/~0/g, '~');
        target = target ? target[part] : undefined;
      }

      const resolved = this.resolveIfRef(target);
      this.resolvedRefs.set(ref, resolved);
      return resolved;
    }

    refLabel(ref) {
      const normalizedRef = String(ref || '');
      const parts = normalizedRef.split('/');
      const label = parts[parts.length - 1];
      if (normalizedRef.startsWith('#/components/schemas/') && label) {
        this.referencedSchemaNames.add(label);
      }
      return '@' + label;
    }

    cleanText(value) {
      return String(value || '').split(/\s+/).filter(Boolean).join(' ');
    }
  }

  let requirements = null;
  let openapi = null;

  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) {
      requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements.md');
    }
    if (!openapi) {
      openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi.yaml');
    }
  }

  if (!requirements) {
    throw new Error('Requirements binary is missing, cannot compact backend context.');
  }
  if (!openapi) {
    throw new Error('OpenAPI binary is missing, cannot compact backend context.');
  }

  const requirementsText = compactRequirementsText(requirements.text);
  if (!requirementsText) {
    throw new Error('Requirements text is empty after compaction.');
  }

  const openapiRaw = normalizeText(openapi.text || '');
  if (!openapiRaw) {
    throw new Error('OpenAPI text is empty, cannot compact specification.');
  }

  let parsedSpec;
  if (openapiRaw.startsWith('{')) {
    try {
      parsedSpec = JSON.parse(openapiRaw);
    } catch {
      parsedSpec = parseYamlDocument(openapiRaw);
    }
  } else {
    parsedSpec = parseYamlDocument(openapiRaw);
  }

  if (!parsedSpec || typeof parsedSpec !== 'object' || !Object.keys(parsedSpec).length) {
    throw new Error('Failed to parse OpenAPI document into a compactable object.');
  }

  const compactedSpec = new OpenApiCompactor(parsedSpec, false).compact();
  const compactedText = JSON.stringify(compactedSpec);

  return [{
    json: {},
    binary: {
      requirements: {
        data: Buffer.from(requirementsText, 'utf8').toString('base64'),
        mimeType: 'text/plain',
        fileExtension: 'txt',
        fileName: 'requirements-compact.txt',
      },
      openapiSpec: {
        data: Buffer.from(compactedText, 'utf8').toString('base64'),
        mimeType: 'application/json',
        fileExtension: 'json',
        fileName: 'openapi-compact.json',
      },
    },
  }];
}

return await beCompactContextArtifacts.call(this);

async function beBuildPrompt() {
  const items = $input.all();
  if (!items.length) {
    throw new Error('Infrastructure structure prompt builder received no input.');
  }

  async function readBinaryText(itemIndex, propertyName, fallbackFileName) {
    const item = items[itemIndex];
    const binary = item.binary?.[propertyName];
    if (!binary) return null;

    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    return {
      fileName: binary.fileName || fallbackFileName,
      text: buffer.toString('utf8'),
    };
  }

  let requirements = null;
  let openapi = null;

  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) {
      requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements-compact.txt');
    }
    if (!openapi) {
      openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi-compact.json');
    }
  }

  if (!requirements) {
    throw new Error('Missing compact requirements binary for infrastructure structure generation.');
  }
  if (!openapi) {
    throw new Error('Missing compact openapiSpec binary for infrastructure structure generation.');
  }

  const requirementsText = String(requirements.text || '').trim();
  const openapiText = String(openapi.text || '').trim();
  if (!requirementsText) {
    throw new Error('Requirements text is empty for infrastructure structure generation.');
  }
  if (!openapiText) {
    throw new Error('OpenAPI text is empty for infrastructure structure generation.');
  }

  const userPrompt = [
    'REQ',
    requirementsText,
    'API',
    openapiText,
  ].join('\n');

  return [{
    json: {
      requirementsFile: requirements.fileName,
      requirementsText,
      requirementsPromptLength: requirementsText.length,
      openapiFile: openapi.fileName || 'openapi-compact.json',
      openapiText,
      openapiPromptLength: openapiText.length,
      userPrompt,
      fullPromptLength: userPrompt.length,
    },
    binary: items[0].binary ?? {},
  }];
}

return await beBuildPrompt.call(this);

function beCleanStructure() {
  function parseJsonCandidate(raw) {
    try {
      const parsed = JSON.parse(raw);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed;
      }
    } catch {}
    return null;
  }

  function normalizeText(raw) {
    let text = String(raw ?? '').trim();
    if (!text) {
      throw new Error('Infrastructure structure model output is empty.');
    }

    if (text.startsWith('```')) {
      const firstNewlineIndex = text.indexOf('\n');
      if (firstNewlineIndex !== -1) {
        const openingFence = text.slice(0, firstNewlineIndex).trim();
        if (/^```(?:json)?$/i.test(openingFence)) {
          text = text.slice(firstNewlineIndex + 1);

          const trailingFenceIndex = text.lastIndexOf('\n```');
          if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
            text = text.slice(0, trailingFenceIndex).trim();
          } else if (text.endsWith('```')) {
            text = text.slice(0, -3).trim();
          } else {
            text = text.trim();
          }
        }
      }
    }

    return text;
  }

  function extractBalancedObject(text) {
    let depth = 0;
    let start = -1;
    let inString = false;
    let escaped = false;

    for (let index = 0; index < text.length; index += 1) {
      const char = text[index];

      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        if (inString) escaped = true;
        continue;
      }

      if (char === '"') {
        inString = !inString;
        continue;
      }

      if (inString) continue;

      if (char === '{') {
        if (depth === 0) start = index;
        depth += 1;
        continue;
      }

      if (char === '}') {
        if (depth > 0) {
          depth -= 1;
          if (depth === 0 && start !== -1) {
            return text.slice(start, index + 1);
          }
        }
      }
    }

    return null;
  }

  function extractStructure(rawText) {
    const text = normalizeText(rawText);
    const candidates = [text];
    const balancedObject = extractBalancedObject(text);
    if (balancedObject) {
      candidates.push(balancedObject);
    }

    for (const candidate of candidates) {
      const parsed = parseJsonCandidate(candidate);
      if (parsed) return parsed;
    }

    throw new Error('Could not extract a valid infrastructure structure JSON document from model output.');
  }

  function normalizeFileEntry(file, index) {
    if (typeof file === 'string') {
      const path = file.trim();
      if (!path) {
        throw new Error(`files[${index}] must not be empty.`);
      }
      return { path };
    }

    if (!file || typeof file !== 'object' || Array.isArray(file)) {
      throw new Error(`files[${index}] must be a string path or an object with path.`);
    }

    const filePath = String(file.path || '').trim();
    if (!filePath) {
      throw new Error(`files[${index}].path is required.`);
    }

    return { path: filePath };
  }

  function validateAndNormalizeStructure(payload) {
    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
      throw new Error('Infrastructure structure must be an object.');
    }
    if (!Array.isArray(payload.files)) {
      throw new Error('Infrastructure structure must contain a files array.');
    }
    if (!payload.files.length) {
      throw new Error('Infrastructure structure files array must not be empty.');
    }

    const seen = new Set();
    const normalizedFiles = payload.files.map((file, index) => {
      const normalized = normalizeFileEntry(file, index);
      const filePath = normalized.path;
      if (!filePath.startsWith('infrastructure/')) {
        throw new Error(`files[${index}].path must start with "infrastructure/".`);
      }
      if (seen.has(filePath)) {
        throw new Error(`Duplicate infrastructure structure file path: ${filePath}`);
      }
      seen.add(filePath);
      return normalized;
    });

    return { files: normalizedFiles };
  }

  const item = $input.first();
  const structure = validateAndNormalizeStructure(extractStructure(item?.json?.text));

  return [{
    json: {
      ...(item?.json ?? {}),
      infrastructureStructure: JSON.stringify(structure, null, 2),
      infrastructureStructureObject: structure,
      structureFileCount: structure.files.length,
    },
    binary: item?.binary ?? {},
  }];
}
return beCleanStructure();

function beInitGenerationState() {
  const item = $input.first();
  if (!item) {
    throw new Error('No infrastructure structure item received.');
  }

  const json = item.json || {};
  const structure = json.infrastructureStructureObject || JSON.parse(String(json.infrastructureStructure || '{}'));
  if (!Array.isArray(structure.files) || !structure.files.length) {
    throw new Error('Infrastructure structure does not contain any files.');
  }

  const seen = new Set();
  const files = structure.files.map((file, index) => {
    const filePath = typeof file === 'string'
      ? String(file).trim()
      : String(file?.path || '').trim();
    if (!filePath.startsWith('infrastructure/')) {
      throw new Error(`Invalid infrastructure structure path at index ${index}: ${filePath || '<empty>'}`);
    }
    if (seen.has(filePath)) {
      throw new Error(`Duplicate infrastructure structure path: ${filePath}`);
    }
    seen.add(filePath);
    return { path: filePath };
  });

  return [{
    json: {
      ...json,
      allPlannedFiles: files,
      remainingFiles: files,
      generatedFiles: [],
      generatedFilePaths: [],
      lastIterationFiles: [],
      totalPlannedFiles: files.length,
      generatedFileCountTotal: 0,
      remainingFileCount: files.length,
      batchSize: 15,
      currentBatchFiles: files.slice(0, 15),
      currentBatchFileCount: Math.min(files.length, 15),
      iteration: 1,
      hasRemainingFiles: 'yes',
    },
    binary: item.binary ?? {},
  }];
}

return beInitGenerationState();

function beBuildChunkPrompt() {
  const MAX_MEMORY_ITEMS = 4;

  function compactJson(value) {
    return JSON.stringify(value);
  }

  function trimImplementationMemory(generatedImplementationIndex, recentImplementationSummaries) {
    const seen = new Set();
    const selected = [];

    for (const collection of [recentImplementationSummaries || [], generatedImplementationIndex || []]) {
      for (const entry of collection) {
        if (!entry || typeof entry !== 'object') continue;
        const path = String(entry.path || '').trim();
        if (!path || seen.has(path)) continue;
        seen.add(path);
        selected.push(entry);
        if (selected.length >= MAX_MEMORY_ITEMS) {
          return selected;
        }
      }
    }

    return selected;
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const requirementsText = String(json.requirementsText || '').trim();
    const openapiText = String(json.openapiText || '').trim();
    if (!requirementsText) throw new Error('Missing requirements text for infrastructure generation.');
    if (!openapiText) throw new Error('Missing OpenAPI text for infrastructure generation.');

    const batchSize = Math.max(1, Number(json.batchSize || 15));
    const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length
      ? json.currentBatchFiles.slice(0, batchSize)
      : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, batchSize) : []);

    if (!currentBatchFiles.length) {
      throw new Error('No current batch files available for infrastructure generation.');
    }

    const allPlannedFiles = Array.isArray(json.allPlannedFiles) && json.allPlannedFiles.length
      ? json.allPlannedFiles
      : currentBatchFiles;
    const allPlannedPaths = allPlannedFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);
    const batchPaths = currentBatchFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);

    const implementationMemory = trimImplementationMemory(
      Array.isArray(json.generatedImplementationIndex) ? json.generatedImplementationIndex : [],
      Array.isArray(json.recentImplementationSummaries) ? json.recentImplementationSummaries : [],
    );

    const userPrompt = [
      'REQ',
      requirementsText,
      'API',
      openapiText,
      'PLAN',
      compactJson(allPlannedPaths),
      'BATCH',
      compactJson(batchPaths),
      'STATE',
      compactJson({
        i: json.iteration,
        g: json.generatedFileCountTotal,
        r: json.remainingFileCount,
        t: allPlannedPaths.length,
        b: batchSize,
        c: currentBatchFiles.length,
      }),
      implementationMemory.length ? 'MEMORY\n' + compactJson(implementationMemory) : '',
      'RULES',
      [
        'Generate only BATCH paths.',
        'PLAN is the full allowed infrastructure path set.',
        'Do not reference types or files outside BATCH, MEMORY, or PLAN.',
        'OpenAPI is absolute truth for paths, methods, params, bodies, fields, status codes, names, and security.',
        'Do not add or rewrite API path prefixes.',
        'Reuse existing naming and generated types consistently.',
        'Return only valid JSON with a top-level files array.',
      ].join('\n'),
    ].filter(Boolean).join('\n');

    return {
      json: {
        ...json,
        batchSize,
        allPlannedFiles,
        currentBatchFiles,
        currentBatchFileCount: currentBatchFiles.length,
        userPrompt,
        requirementsPromptLength: requirementsText.length,
        openapiPromptLength: openapiText.length,
        implementationMemoryLength: compactJson(implementationMemory).length,
        fullPromptLength: userPrompt.length,
      },
      binary: item.binary ?? {},
    };
  });
}

return beBuildChunkPrompt();

