      const imports = uniqueStrings(matchAll(content, /^[ \t]*import\s+([^;]+);/gm, (m) => m[1], 40), 40);
      const annotations = uniqueStrings(matchAll(content, /^[ \t]*@([A-Za-z0-9_.]+)/gm, (m) => m[1], 30), 30);
      const types = matchAll(content, /^[ \t]*(?:public|protected|private)?\s*(?:abstract|final|sealed|non-sealed)?\s*(class|interface|enum|record)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 20);
      const methods = matchAll(content, /^[ \t]*(?:public|protected|private)\s+(?:static\s+)?(?:final\s+)?(?:<[A-Za-z0-9_, ? extends implements]+>\s+)?([A-Za-z0-9_\[\]<>., ?]+)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[2], returns: m[1].trim(), parameters: String(m[3] || '').trim() }), 40);
