        ...matchAll(content, /^[ \t]*import\s+(.+)$/gm, (m) => m[1], 40),
        ...matchAll(content, /^[ \t]*from\s+(.+)\s+import\s+(.+)$/gm, (m) => 'from ' + m[1] + ' import ' + m[2], 40),
      ], 40);
      const decorators = uniqueStrings(matchAll(content, /^[ \t]*@([A-Za-z0-9_.]+)/gm, (m) => m[1], 30), 30);
      const classes = matchAll(content, /^[ \t]*class\s+([A-Za-z0-9_]+)(?:\(([^\)]*)\))?\s*:/gm, (m) => ({ name: m[1], bases: String(m[2] || '').trim() }), 20);
      const functions = matchAll(content, /^[ \t]*def\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)\s*(?:->\s*([^:]+))?:/gm, (m) => ({ name: m[1], parameters: String(m[2] || '').trim(), returns: String(m[3] || '').trim() }), 40);
