      const attributes = uniqueStrings(matchAll(content, /^[ \t]*\[([A-Za-z0-9_., ()]+)\]/gm, (m) => m[1], 30), 30);
      const types = matchAll(content, /^[ \t]*(?:public|internal|protected|private)?\s*(?:abstract|sealed|partial)?\s*(class|interface|enum|record|struct)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 20);
