    function summarizeGo(filePath, content) {
      const pkg = content.match(/^[ \t]*package\s+([A-Za-z0-9_]+)/m)?.[1] || '';
      const imports = uniqueStrings([
        ...matchAll(content, /^[ \t]*import\s+"([^"]+)"/gm, (m) => m[1], 40),
        ...matchAll(content, /^[ \t]*"([^"]+)"$/gm, (m) => m[1], 40),
      ], 40);
      const types = matchAll(content, /^[ \t]*type\s+([A-Za-z0-9_]+)\s+(struct|interface)/gm, (m) => ({ name: m[1], kind: m[2] }), 20);
      const functions = [
        ...matchAll(content, /^[ \t]*func\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[1], receiver: '', parameters: String(m[2] || '').trim() }), 40),
        ...matchAll(content, /^[ \t]*func\s*\(([^\)]*)\)\s*([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[2], receiver: String(m[1] || '').trim(), parameters: String(m[3] || '').trim() }), 40),
      ].slice(0, 40);
      return { path: filePath, language: 'go', package: pkg, imports, types, functions };
    }

    function summarizeGeneric(filePath, content, language) {
      const imports = uniqueStrings([
        ...matchAll(content, /^[ \t]*import\s+(.+)$/gm, (m) => m[1], 20),
        ...matchAll(content, /^[ \t]*using\s+([^;]+);/gm, (m) => m[1], 20),
