function beAssembleBackendZipInputs() {
    function getExtension(filePath) {
      const fileName = String(filePath || '').split('/').pop() || '';
      if (fileName === 'pom.xml') return 'xml';
      if (fileName === '.gitignore') return 'gitignore';
      const match = fileName.match(/\.([A-Za-z0-9]+)$/);
      return match ? match[1].toLowerCase() : 'txt';
    }

    function getMimeType(filePath) {
      const ext = getExtension(filePath);
      const mimeByExtension = {
        java: 'text/x-java-source',
        xml: 'application/xml',
        yaml: 'text/yaml',
        yml: 'text/yaml',
        json: 'application/json',
        properties: 'text/plain',
        md: 'text/markdown',
        txt: 'text/plain',
        sql: 'application/sql',
        csv: 'text/csv',
        gitignore: 'text/plain',
      };
      return mimeByExtension[ext] || 'text/plain';
    }

    function isIntentionallyEmptyFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('/.gitkeep') || lower.endsWith('/.keep') || lower.endsWith('/.placeholder');
    }

    function normalizeContent(contentValue) {
      if (typeof contentValue === 'string') {
        return contentValue;
      }
      if (contentValue === null || contentValue === undefined) {
        return '';
      }
      if (typeof contentValue === 'object') {
        return JSON.stringify(contentValue, null, 2);
      }
      return String(contentValue);
    }

    const item = $input.first();
    if (!item) {
      throw new Error('No infrastructure generation state available for ZIP assembly.');
    }

    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];

    if (remainingFiles.length > 0) {
      throw new Error('Cannot assemble infrastructure ZIP while files are still remaining.');
    }
    if (!generatedFiles.length) {
      throw new Error('No generated infrastructure files available to assemble ZIP.');
    }

    const binary = {};
    const manifest = [];

    generatedFiles.forEach((file, index) => {
      const filePath = String(file?.path || '').trim();
      const content = normalizeContent(file?.content);
      if (!filePath.startsWith('infrastructure/')) {
        throw new Error(`Generated infrastructure file path must start with "infrastructure/": ${filePath || '<empty>'}`);
      }
      if (!content.trim() && !isIntentionallyEmptyFile(filePath)) {
        throw new Error(`Generated infrastructure file content is empty for: ${filePath}`);
      }

