async function beBuildPrompt() {
  const items = $input.all();
  if (!items.length) {
    throw new Error('Tests structure prompt builder received no input.');
  }

  async function readBinaryText(itemIndex, propertyName, fallbackFileName) {
    const item = items[itemIndex];
    const binary = item.binary?.[propertyName];
    if (!binary) return null;

    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    return {
      fileName: binary.fileName || fallbackFileName,
      text: buffer.toString('utf8'),
    };
  }

  let requirements = null;
  let openapi = null;

  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) {
      requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements-compact.txt');
    }
    if (!openapi) {
      openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi-compact.json');
    }
  }

  if (!requirements) {
    throw new Error('Missing compact requirements binary for tests structure generation.');
  }
  if (!openapi) {
    throw new Error('Missing compact openapiSpec binary for tests structure generation.');
  }

  const requirementsText = String(requirements.text || '').trim();
  const openapiText = String(openapi.text || '').trim();
  if (!requirementsText) {
    throw new Error('Requirements text is empty for tests structure generation.');
  }
  if (!openapiText) {
    throw new Error('OpenAPI text is empty for tests structure generation.');
  }

  const userPrompt = [
    'REQ',
    requirementsText,
    'API',
    openapiText,
  ].join('\n');

  return [{
    json: {
      requirementsFile: requirements.fileName,
      requirementsText,
      requirementsPromptLength: requirementsText.length,
      openapiFile: openapi.fileName || 'openapi-compact.json',
      openapiText,
      openapiPromptLength: openapiText.length,
      userPrompt,
      fullPromptLength: userPrompt.length,
    },
    binary: items[0].binary ?? {},
  }];
}

return await beBuildPrompt.call(this);

function beCleanStructure() {
  function parseJsonCandidate(raw) {
    try {
      const parsed = JSON.parse(raw);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed;
      }
    } catch {}
    return null;
  }

  function normalizeText(raw) {
    let text = String(raw ?? '').trim();
    if (!text) {
      throw new Error('Tests structure model output is empty.');
    }

    if (text.startsWith('```')) {
      const firstNewlineIndex = text.indexOf('\n');
      if (firstNewlineIndex !== -1) {
        const openingFence = text.slice(0, firstNewlineIndex).trim();
        if (/^```(?:json)?$/i.test(openingFence)) {
          text = text.slice(firstNewlineIndex + 1);

          const trailingFenceIndex = text.lastIndexOf('\n```');
          if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
            text = text.slice(0, trailingFenceIndex).trim();
          } else if (text.endsWith('```')) {
            text = text.slice(0, -3).trim();
          } else {
            text = text.trim();
          }
        }
      }
    }

    return text;
  }

  function extractBalancedObject(text) {
    let depth = 0;
    let start = -1;
    let inString = false;
    let escaped = false;

    for (let index = 0; index < text.length; index += 1) {
      const char = text[index];

      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        if (inString) escaped = true;
        continue;
      }

      if (char === '"') {
        inString = !inString;
        continue;
      }

      if (inString) continue;

      if (char === '{') {
        if (depth === 0) start = index;
        depth += 1;
        continue;
      }

      if (char === '}') {
        if (depth > 0) {
          depth -= 1;
          if (depth === 0 && start !== -1) {
            return text.slice(start, index + 1);
          }
        }
      }
    }

    return null;
  }

  function extractStructure(rawText) {
    const text = normalizeText(rawText);
    const candidates = [text];
    const balancedObject = extractBalancedObject(text);
    if (balancedObject) {
      candidates.push(balancedObject);
    }

    for (const candidate of candidates) {
      const parsed = parseJsonCandidate(candidate);
      if (parsed) return parsed;
    }

    throw new Error('Could not extract a valid tests structure JSON document from model output.');
  }

  function normalizeFileEntry(file, index) {
    if (typeof file === 'string') {
      const path = file.trim();
      if (!path) {
        throw new Error(`files[${index}] must not be empty.`);
      }
      return { path };
    }

    if (!file || typeof file !== 'object' || Array.isArray(file)) {
      throw new Error(`files[${index}] must be a string path or an object with path.`);
    }

    const filePath = String(file.path || '').trim();
    if (!filePath) {
      throw new Error(`files[${index}].path is required.`);
    }

    return { path: filePath };
  }

  function validateAndNormalizeStructure(payload) {
    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
      throw new Error('Tests structure must be an object.');
    }
    if (!Array.isArray(payload.files)) {
      throw new Error('Tests structure must contain a files array.');
    }
    if (!payload.files.length) {
      throw new Error('Tests structure files array must not be empty.');
    }

    const seen = new Set();
    const normalizedFiles = payload.files.map((file, index) => {
      const normalized = normalizeFileEntry(file, index);
      const filePath = normalized.path;
      if (!filePath.startsWith('tests/')) {
        throw new Error(`files[${index}].path must start with "tests/".`);
      }
      if (seen.has(filePath)) {
        throw new Error(`Duplicate tests structure file path: ${filePath}`);
      }
      seen.add(filePath);
      return normalized;
    });

    return { files: normalizedFiles };
  }

  const item = $input.first();
  const structure = validateAndNormalizeStructure(extractStructure(item?.json?.text));

  return [{
    json: {
      ...(item?.json ?? {}),
      testsStructure: JSON.stringify(structure, null, 2),
      testsStructureObject: structure,
      structureFileCount: structure.files.length,
    },
    binary: item?.binary ?? {},
  }];
}
return beCleanStructure();

function beInitGenerationState() {
  const item = $input.first();
  if (!item) {
    throw new Error('No tests structure item received.');
  }

  const json = item.json || {};
  const structure = json.testsStructureObject || JSON.parse(String(json.testsStructure || '{}'));
  if (!Array.isArray(structure.files) || !structure.files.length) {
    throw new Error('Tests structure does not contain any files.');
  }

  const seen = new Set();
  const files = structure.files.map((file, index) => {
    const filePath = typeof file === 'string'
      ? String(file).trim()
      : String(file?.path || '').trim();
    if (!filePath.startsWith('tests/')) {
      throw new Error(`Invalid tests structure path at index ${index}: ${filePath || '<empty>'}`);
    }
    if (seen.has(filePath)) {
      throw new Error(`Duplicate tests structure path: ${filePath}`);
    }
    seen.add(filePath);
    return { path: filePath };
  });

  return [{
    json: {
      ...json,
      allPlannedFiles: files,
      remainingFiles: files,
      generatedFiles: [],
      generatedFilePaths: [],
      lastIterationFiles: [],
      totalPlannedFiles: files.length,
      generatedFileCountTotal: 0,
      remainingFileCount: files.length,
      batchSize: 15,
      currentBatchFiles: files.slice(0, 15),
      currentBatchFileCount: Math.min(files.length, 15),
      iteration: 1,
      hasRemainingFiles: 'yes',
    },
    binary: item.binary ?? {},
  }];
}

return beInitGenerationState();

function beBuildChunkPrompt() {
  const MAX_MEMORY_ITEMS = 4;

  function compactJson(value) {
    return JSON.stringify(value);
  }

  function trimImplementationMemory(generatedImplementationIndex, recentImplementationSummaries) {
    const seen = new Set();
    const selected = [];

    for (const collection of [recentImplementationSummaries || [], generatedImplementationIndex || []]) {
      for (const entry of collection) {
        if (!entry || typeof entry !== 'object') continue;
        const path = String(entry.path || '').trim();
        if (!path || seen.has(path)) continue;
        seen.add(path);
        selected.push(entry);
        if (selected.length >= MAX_MEMORY_ITEMS) {
          return selected;
        }
      }
    }

    return selected;
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const requirementsText = String(json.requirementsText || '').trim();
    const openapiText = String(json.openapiText || '').trim();
    if (!requirementsText) throw new Error('Missing requirements text for tests generation.');
    if (!openapiText) throw new Error('Missing OpenAPI text for tests generation.');

    const batchSize = Math.max(1, Number(json.batchSize || 15));
    const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length
      ? json.currentBatchFiles.slice(0, batchSize)
      : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, batchSize) : []);

    if (!currentBatchFiles.length) {
      throw new Error('No current batch files available for tests generation.');
    }

    const allPlannedFiles = Array.isArray(json.allPlannedFiles) && json.allPlannedFiles.length
      ? json.allPlannedFiles
      : currentBatchFiles;
    const allPlannedPaths = allPlannedFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);
    const batchPaths = currentBatchFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);

    const implementationMemory = trimImplementationMemory(
      Array.isArray(json.generatedImplementationIndex) ? json.generatedImplementationIndex : [],
      Array.isArray(json.recentImplementationSummaries) ? json.recentImplementationSummaries : [],
    );

    const userPrompt = [
      'REQ',
      requirementsText,
      'API',
      openapiText,
      'PLAN',
      compactJson(allPlannedPaths),
      'BATCH',
      compactJson(batchPaths),
      'STATE',
      compactJson({
        i: json.iteration,
        g: json.generatedFileCountTotal,
        r: json.remainingFileCount,
        t: allPlannedPaths.length,
        b: batchSize,
        c: currentBatchFiles.length,
      }),
      implementationMemory.length ? 'MEMORY\n' + compactJson(implementationMemory) : '',
      'RULES',
      [
        'Generate only BATCH paths.',
        'PLAN is the full allowed tests path set.',
        'Do not reference types or files outside BATCH, MEMORY, or PLAN.',
        'OpenAPI is absolute truth for paths, methods, params, bodies, fields, status codes, names, and security.',
        'Do not add or rewrite API path prefixes.',
        'Reuse existing naming and generated types consistently.',
        'Return only valid JSON with a top-level files array.',
      ].join('\n'),
    ].filter(Boolean).join('\n');

    return {
      json: {
        ...json,
        batchSize,
        allPlannedFiles,
        currentBatchFiles,
        currentBatchFileCount: currentBatchFiles.length,
        userPrompt,
        requirementsPromptLength: requirementsText.length,
        openapiPromptLength: openapiText.length,
        implementationMemoryLength: compactJson(implementationMemory).length,
        fullPromptLength: userPrompt.length,
      },
      binary: item.binary ?? {},
    };
  });
}

return beBuildChunkPrompt();

function beCleanChunkResponse() {
    function parseCandidate(raw) {
      try {
        const parsed = JSON.parse(raw);
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
          return parsed;
        }
      } catch {}
      return null;
    }

    function normalizeText(raw) {
      let text = String(raw ?? '').trim();
      if (!text) {
        throw new Error('Backend chunk model output is empty.');
      }

      if (text.startsWith('```')) {
        const firstNewlineIndex = text.indexOf('\n');
        if (firstNewlineIndex !== -1) {
          const openingFence = text.slice(0, firstNewlineIndex).trim();
          if (/^\`\`\`(?:json)?$/i.test(openingFence)) {
            text = text.slice(firstNewlineIndex + 1);
            const trailingFenceIndex = text.lastIndexOf('\n\`\`\`');
            if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
              text = text.slice(0, trailingFenceIndex).trim();
            } else if (text.endsWith('```')) {
              text = text.slice(0, -3).trim();
            } else {
              text = text.trim();
            }
          }
        }
      }

      return text;
    }

    function extractBalancedObject(text) {
      let depth = 0;
      let start = -1;
      let inString = false;
      let escaped = false;

      for (let index = 0; index < text.length; index += 1) {
        const char = text[index];

        if (escaped) {
          escaped = false;
          continue;
        }

        if (char === '\\') {
          if (inString) escaped = true;
          continue;
        }

        if (char === '"') {
          inString = !inString;
          continue;
        }

        if (inString) continue;

        if (char === '{') {
          if (depth === 0) start = index;
          depth += 1;
          continue;
        }

        if (char === '}') {
          if (depth > 0) {
            depth -= 1;
            if (depth === 0 && start !== -1) {
              return text.slice(start, index + 1);
            }
          }
        }
      }

      return null;
    }

    function isQuoteEscaped(text, quoteIndex) {
      let backslashCount = 0;
      for (let index = quoteIndex - 1; index >= 0 && text[index] === '\\'; index -= 1) {
        backslashCount += 1;
      }
      return backslashCount % 2 === 1;
    }

    function findPropertyKey(text, key, fromIndex) {
      const pattern = '"' + key + '"';
      return text.indexOf(pattern, fromIndex);
    }

    function findValueQuoteStart(text, keyIndex) {
      const colonIndex = text.indexOf(':', keyIndex);
      if (colonIndex === -1) return -1;
      for (let index = colonIndex + 1; index < text.length; index += 1) {
        const char = text[index];
        if (/\s/.test(char)) continue;
        return char === '"' ? index : -1;
      }
      return -1;
    }

    function decodeLooseJsonString(raw) {
      let output = '';

      for (let index = 0; index < raw.length; index += 1) {
        const char = raw[index];
        if (char !== '\\') {
          output += char;
          continue;
        }

        const next = raw[index + 1];
        if (next === undefined) {
          output += '\\';
          break;
        }

        if (next === 'n') {
          output += '\n';
          index += 1;
          continue;
        }
        if (next === 'r') {
          output += '\r';
          index += 1;
          continue;
        }
        if (next === 't') {
          output += '\t';
          index += 1;
          continue;
        }
        if (next === 'b') {
          output += '\b';
          index += 1;
          continue;
        }
        if (next === 'f') {
          output += '\f';
          index += 1;
          continue;
        }
        if (next === '"' || next === '\\' || next === '/') {
          output += next;
          index += 1;
          continue;
        }
        if (next === 'u' && /^[0-9a-fA-F]{4}$/.test(raw.slice(index + 2, index + 6))) {
          output += String.fromCharCode(parseInt(raw.slice(index + 2, index + 6), 16));
          index += 5;
          continue;
        }

        output += '\\' + next;
        index += 1;
      }

      return output;
    }

    function readStrictQuotedString(text, quoteStart) {
      for (let index = quoteStart + 1; index < text.length; index += 1) {
        if (text[index] === '"' && !isQuoteEscaped(text, index)) {
          return {
            value: decodeLooseJsonString(text.slice(quoteStart + 1, index)),
            endIndex: index,
          };
        }
      }
      throw new Error('Could not find closing quote for JSON string.');
    }

    function readContentQuotedString(text, quoteStart) {
      for (let index = quoteStart + 1; index < text.length; index += 1) {
        if (text[index] !== '"' || isQuoteEscaped(text, index)) continue;

        let lookahead = index + 1;
        while (lookahead < text.length && /\s/.test(text[lookahead])) {
          lookahead += 1;
        }

        if (text[lookahead] === '}') {
          return {
            value: decodeLooseJsonString(text.slice(quoteStart + 1, index)),
            endIndex: index,
          };
        }
      }

      throw new Error('Could not find closing quote for generated file content.');
    }

    function canRecoverTruncatedTextFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('.md') || lower.endsWith('.txt');
    }

    function decodeLooseJsonTail(raw) {
      let tail = String(raw || '');
      if (tail.endsWith('```')) {
        tail = tail.slice(0, -3);
      }
      return decodeLooseJsonString(tail).trimEnd();
    }

    function isLikelyIncompletePayloadError(error) {
      const message = String(error?.message ?? error ?? '');
      return (
        message.includes('Could not find closing quote') ||
        message.includes('did not end after content field') ||
        message.includes('files array was not closed') ||
        message.includes('ended before files array closed') ||
        message.includes('Could not find content string value')
      );
    }

    function parseLooseFilesPayload(text, allowPartial = false) {
      const filesKeyIndex = findPropertyKey(text, 'files', 0);
      if (filesKeyIndex === -1) {
        throw new Error('Chunk payload does not contain a files property.');
      }

      const arrayStart = text.indexOf('[', filesKeyIndex);
      if (arrayStart === -1) {
        throw new Error('Chunk payload files property does not contain an array.');
      }

      const files = [];
      let cursor = arrayStart + 1;

      while (cursor < text.length) {
        while (cursor < text.length && /[\s,]/.test(text[cursor])) cursor += 1;
        if (cursor >= text.length) {
          if (allowPartial) {
            return {
              files,
              recoveredPartialChunkPayload: true,
              ignoredIncompleteTrailingFile: true,
              recoveryReason: files.length
                ? 'Chunk payload ended before files array closed.'
                : 'Ignored incomplete trailing generated file because the model output ended before the payload closed.',
            };
          }
          break;
        }
        if (text[cursor] === ']') {
          return { files };
        }
        if (text[cursor] !== '{') {
          cursor += 1;
          continue;
        }

        let pathInfo = null;
        let contentQuoteStart = -1;

        try {
          const objectStart = cursor;
          const pathKeyIndex = findPropertyKey(text, 'path', objectStart);
          if (pathKeyIndex === -1) {
            throw new Error('Could not find path property in generated file object.');
          }
          const pathQuoteStart = findValueQuoteStart(text, pathKeyIndex);
          if (pathQuoteStart === -1) {
            throw new Error('Could not find path string value in generated file object.');
          }
          pathInfo = readStrictQuotedString(text, pathQuoteStart);

          const contentKeyIndex = findPropertyKey(text, 'content', pathInfo.endIndex);
          if (contentKeyIndex === -1) {
            throw new Error('Could not find content property in generated file object.');
          }
          contentQuoteStart = findValueQuoteStart(text, contentKeyIndex);
          if (contentQuoteStart === -1) {
            throw new Error('Could not find content string value in generated file object.');
          }
          const contentInfo = readContentQuotedString(text, contentQuoteStart);

          let objectEnd = contentInfo.endIndex + 1;
          while (objectEnd < text.length && /\s/.test(text[objectEnd])) objectEnd += 1;
          if (text[objectEnd] !== '}') {
            throw new Error('Generated file object did not end after content field.');
          }

          files.push({
            path: pathInfo.value,
            content: contentInfo.value,
          });

          cursor = objectEnd + 1;
        } catch (error) {
          if (allowPartial && pathInfo && contentQuoteStart !== -1 && canRecoverTruncatedTextFile(pathInfo.value)) {
            const recoveredContent = decodeLooseJsonTail(text.slice(contentQuoteStart + 1));
            if (recoveredContent.trim()) {
              files.push({
                path: pathInfo.value,
                content: recoveredContent,
              });
              return {
                files,
                recoveredPartialChunkPayload: true,
                recoveryReason: 'Recovered truncated text file content for ' + pathInfo.value,
              };
            }
          }
          if (allowPartial && (files.length || isLikelyIncompletePayloadError(error))) {
            return {
              files,
              recoveredPartialChunkPayload: true,
              ignoredIncompleteTrailingFile: true,
              recoveryReason: files.length
                ? String(error?.message ?? error ?? 'Partial chunk payload recovered.')
                : 'Ignored incomplete trailing generated file because the model output ended before the file was complete.',
            };
          }
          throw error;
        }
      }

      if (allowPartial) {
        return {
          files,
          recoveredPartialChunkPayload: true,
          ignoredIncompleteTrailingFile: true,
          recoveryReason: files.length
            ? 'Chunk payload files array was not closed.'
            : 'Ignored incomplete trailing generated file because the files array was not closed.',
        };
      }

      throw new Error('Chunk payload files array was not closed.');
    }

    function extractPayload(rawText) {
      const text = normalizeText(rawText);
      const candidates = [text];
      const balancedObject = extractBalancedObject(text);
      if (balancedObject) {
        candidates.push(balancedObject);
      }

      for (const candidate of candidates) {
        const parsed = parseCandidate(candidate);
        if (parsed) return parsed;
      }

      for (const candidate of candidates) {
        try {
          const parsed = parseLooseFilesPayload(candidate, false);
          if (parsed && Array.isArray(parsed.files)) {
            return parsed;
          }
        } catch {}
      }

      for (const candidate of candidates) {
        try {
          const parsed = parseLooseFilesPayload(candidate, true);
          if (parsed && Array.isArray(parsed.files)) {
            return parsed;
          }
        } catch {}
      }

      throw new Error('Could not extract a valid backend chunk JSON payload from model output.');
    }

    function getNodeItemsSafe(nodeName) {
      if (typeof $items !== 'function') return [];
      try {
        return $items(nodeName) || [];
      } catch (error) {
        const message = String(error?.message ?? error ?? '');
        if (message.includes("hasn't been executed") || message.includes('not executed')) {
          return [];
        }
        throw error;
      }
    }

    function isIntentionallyEmptyFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('/.gitkeep') || lower.endsWith('/.keep') || lower.endsWith('/.placeholder');
    }

    function normalizeGeneratedContent(filePath, contentValue) {
      if (typeof contentValue === 'string') {
        return contentValue;
      }
      if (contentValue === null || contentValue === undefined) {
        return '';
      }
      if (typeof contentValue === 'object') {
        return JSON.stringify(contentValue, null, 2);
      }
      return String(contentValue);
    }

    const buildPromptItems = getNodeItemsSafe('TEST - Build Chunk Prompt');

    return $input.all().map((item) => {
      const upstreamJson = buildPromptItems[0]?.json || {};
      const json = {
        ...upstreamJson,
        ...(item.json || {}),
      };
      const payload = extractPayload(json.text);
      const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length
        ? json.currentBatchFiles
        : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, Number(json.batchSize || 15)) : []);
      const currentBatchPaths = new Set(currentBatchFiles.map((file) => String(file.path || '').trim()).filter(Boolean));
      const plannedFiles = Array.isArray(json.allPlannedFiles) && json.allPlannedFiles.length
        ? json.allPlannedFiles
        : (Array.isArray(json.backendStructure) ? json.backendStructure : []);
      const allowedPaths = new Set(plannedFiles.map((file) => String(file.path || '').trim()).filter(Boolean));
      const generatedOutsideCurrentBatch = [];
      const ignoredUnplannedGeneratedFiles = [];
      const ignoredDuplicateGeneratedFiles = [];

      if (!Array.isArray(payload.files)) {
        throw new Error('Chunk payload must include a files array.');
      }

      const seen = new Set();
      const normalizedFiles = [];
      for (let index = 0; index < payload.files.length; index += 1) {
        const file = payload.files[index];
        if (!file || typeof file !== 'object' || Array.isArray(file)) {
          throw new Error('Generated file entry at index ' + index + ' must be an object.');
        }

        const filePath = String(file.path || '').trim();
        const content = normalizeGeneratedContent(filePath, file.content);
        if (!filePath.startsWith('tests/')) {
          throw new Error('Generated invalid file path: ' + (filePath || '<empty>'));
        }
        if (!allowedPaths.has(filePath)) {
          ignoredUnplannedGeneratedFiles.push(filePath);
          continue;
        }
        if (!currentBatchPaths.has(filePath)) {
          generatedOutsideCurrentBatch.push(filePath);
        }
        if (seen.has(filePath)) {
          ignoredDuplicateGeneratedFiles.push(filePath);
          continue;
        }
        if (!content.trim() && !isIntentionallyEmptyFile(filePath)) {
          throw new Error('Generated empty file content for: ' + filePath);
        }

        seen.add(filePath);
        normalizedFiles.push({
          path: filePath,
          content,
        });
      }

      return {
        json: {
          ...json,
          recoveredPartialChunkPayload: payload.recoveredPartialChunkPayload === true,
          partialChunkRecoveryReason: payload.recoveryReason || '',
          ignoredIncompleteTrailingFile: payload.ignoredIncompleteTrailingFile === true,
          generatedFilesThisIteration: normalizedFiles,
          generatedFileCountThisIteration: normalizedFiles.length,
          generatedFilesOutsideCurrentBatch: generatedOutsideCurrentBatch,
          generatedFilesOutsideCurrentBatchCount: generatedOutsideCurrentBatch.length,
          ignoredUnplannedGeneratedFiles,
          ignoredUnplannedGeneratedFileCount: ignoredUnplannedGeneratedFiles.length,
          ignoredDuplicateGeneratedFiles,
          ignoredDuplicateGeneratedFileCount: ignoredDuplicateGeneratedFiles.length,
        },
        binary: item.binary ?? {},
      };
    });
  }
return beCleanChunkResponse();

function beUpdateGenerationState() {
    function detectLanguage(filePath) {
      const lower = String(filePath || '').toLowerCase();
      if (lower.endsWith('.java')) return 'java';
      if (lower.endsWith('.kt')) return 'kotlin';
      if (lower.endsWith('.py')) return 'python';
      if (lower.endsWith('.ts')) return 'typescript';
      if (lower.endsWith('.tsx')) return 'tsx';
      if (lower.endsWith('.js')) return 'javascript';
      if (lower.endsWith('.jsx')) return 'jsx';
      if (lower.endsWith('.cs')) return 'csharp';
      if (lower.endsWith('.go')) return 'go';
      if (lower.endsWith('.rb')) return 'ruby';
      if (lower.endsWith('.php')) return 'php';
      if (lower.endsWith('.rs')) return 'rust';
      if (lower.endsWith('.swift')) return 'swift';
      if (lower.endsWith('.scala')) return 'scala';
      if (lower.endsWith('.c')) return 'c';
      if (lower.endsWith('.cpp') || lower.endsWith('.cc') || lower.endsWith('.cxx')) return 'cpp';
      if (lower.endsWith('.h') || lower.endsWith('.hpp')) return 'cpp-header';
      return 'other';
    }

    function isImplementationFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      if (!lower.startsWith('tests/')) return false;
      if (lower.includes('/src/test/') || lower.includes('/tests/') || lower.includes('/test/')) return false;
      if (lower.includes('/resources/') || lower.includes('/db/') || lower.includes('/docs/') || lower.includes('/helm/')) return false;
      if (lower.endsWith('.md') || lower.endsWith('.txt') || lower.endsWith('.yaml') || lower.endsWith('.yml') || lower.endsWith('.xml') || lower.endsWith('.properties') || lower.endsWith('.sql') || lower.endsWith('.json') || lower.endsWith('.csv')) return false;
      return new Set(['java', 'kotlin', 'python', 'typescript', 'tsx', 'javascript', 'jsx', 'csharp', 'go', 'ruby', 'php', 'rust', 'swift', 'scala', 'c', 'cpp', 'cpp-header']).has(detectLanguage(filePath));
    }

    function uniqueStrings(values, limit) {
      const seen = new Set();
      const output = [];
      for (const value of values || []) {
        const normalized = String(value || '').trim();
        if (!normalized || seen.has(normalized)) continue;
        seen.add(normalized);
        output.push(normalized);
        if (output.length >= limit) break;
      }
      return output;
    }

    function matchAll(text, regex, mapper, limit) {
      const output = [];
      let match;
      while ((match = regex.exec(text)) !== null) {
        output.push(mapper(match));
        if (output.length >= limit) break;
      }
      regex.lastIndex = 0;
      return output;
    }

    function summarizeJava(filePath, content) {
      const pkg = content.match(/^[ \t]*package\s+([A-Za-z0-9_.]+)\s*;/m)?.[1] || '';
      const imports = uniqueStrings(matchAll(content, /^[ \t]*import\s+([^;]+);/gm, (m) => m[1], 40), 40);
      const annotations = uniqueStrings(matchAll(content, /^[ \t]*@([A-Za-z0-9_.]+)/gm, (m) => m[1], 30), 30);
      const types = matchAll(content, /^[ \t]*(?:public|protected|private)?\s*(?:abstract|final|sealed|non-sealed)?\s*(class|interface|enum|record)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 20);
      const methods = matchAll(content, /^[ \t]*(?:public|protected|private)\s+(?:static\s+)?(?:final\s+)?(?:<[A-Za-z0-9_, ? extends implements]+>\s+)?([A-Za-z0-9_\[\]<>., ?]+)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[2], returns: m[1].trim(), parameters: String(m[3] || '').trim() }), 40);
      return { path: filePath, language: 'java', package: pkg, imports, annotations, types, methods };
    }

    function summarizePython(filePath, content) {
      const imports = uniqueStrings([
        ...matchAll(content, /^[ \t]*import\s+(.+)$/gm, (m) => m[1], 40),
        ...matchAll(content, /^[ \t]*from\s+(.+)\s+import\s+(.+)$/gm, (m) => 'from ' + m[1] + ' import ' + m[2], 40),
      ], 40);
      const decorators = uniqueStrings(matchAll(content, /^[ \t]*@([A-Za-z0-9_.]+)/gm, (m) => m[1], 30), 30);
      const classes = matchAll(content, /^[ \t]*class\s+([A-Za-z0-9_]+)(?:\(([^\)]*)\))?\s*:/gm, (m) => ({ name: m[1], bases: String(m[2] || '').trim() }), 20);
      const functions = matchAll(content, /^[ \t]*def\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)\s*(?:->\s*([^:]+))?:/gm, (m) => ({ name: m[1], parameters: String(m[2] || '').trim(), returns: String(m[3] || '').trim() }), 40);
      return { path: filePath, language: 'python', imports, decorators, classes, functions };
    }

    function summarizeTsLike(filePath, content, language) {
      const imports = uniqueStrings(matchAll(content, /^[ \t]*import\s+(.+)$/gm, (m) => m[1], 40), 40);
      const exports = uniqueStrings(matchAll(content, /^[ \t]*export\s+(?:default\s+)?(?:class|interface|enum|type|function|const)\s+([A-Za-z0-9_]+)/gm, (m) => m[1], 30), 30);
      const decorators = uniqueStrings(matchAll(content, /^[ \t]*@([A-Za-z0-9_.]+)/gm, (m) => m[1], 30), 30);
      const types = matchAll(content, /^[ \t]*(?:export\s+)?(?:abstract\s+)?(class|interface|enum|type)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 25);
      const functions = matchAll(content, /^[ \t]*(?:export\s+)?(?:async\s+)?function\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[1], parameters: String(m[2] || '').trim() }), 40);
      return { path: filePath, language, imports, decorators, exports, types, functions };
    }

    function summarizeCSharp(filePath, content) {
      const namespaceName = content.match(/^[ \t]*namespace\s+([A-Za-z0-9_.]+)/m)?.[1] || '';
      const usings = uniqueStrings(matchAll(content, /^[ \t]*using\s+([^;]+);/gm, (m) => m[1], 40), 40);
      const attributes = uniqueStrings(matchAll(content, /^[ \t]*\[([A-Za-z0-9_., ()]+)\]/gm, (m) => m[1], 30), 30);
      const types = matchAll(content, /^[ \t]*(?:public|internal|protected|private)?\s*(?:abstract|sealed|partial)?\s*(class|interface|enum|record|struct)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 20);
      const methods = matchAll(content, /^[ \t]*(?:public|protected|private|internal)\s+(?:static\s+)?(?:async\s+)?([A-Za-z0-9_<>,.?\[\] ]+)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[2], returns: m[1].trim(), parameters: String(m[3] || '').trim() }), 40);
      return { path: filePath, language: 'csharp', namespace: namespaceName, usings, attributes, types, methods };
    }

    function summarizeGo(filePath, content) {
      const pkg = content.match(/^[ \t]*package\s+([A-Za-z0-9_]+)/m)?.[1] || '';
      const imports = uniqueStrings([
        ...matchAll(content, /^[ \t]*import\s+"([^"]+)"/gm, (m) => m[1], 40),
        ...matchAll(content, /^[ \t]*"([^"]+)"$/gm, (m) => m[1], 40),
      ], 40);
      const types = matchAll(content, /^[ \t]*type\s+([A-Za-z0-9_]+)\s+(struct|interface)/gm, (m) => ({ name: m[1], kind: m[2] }), 20);
      const functions = [
        ...matchAll(content, /^[ \t]*func\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[1], receiver: '', parameters: String(m[2] || '').trim() }), 40),
        ...matchAll(content, /^[ \t]*func\s*\(([^\)]*)\)\s*([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[2], receiver: String(m[1] || '').trim(), parameters: String(m[3] || '').trim() }), 40),
      ].slice(0, 40);
      return { path: filePath, language: 'go', package: pkg, imports, types, functions };
    }

    function summarizeGeneric(filePath, content, language) {
      const imports = uniqueStrings([
        ...matchAll(content, /^[ \t]*import\s+(.+)$/gm, (m) => m[1], 20),
        ...matchAll(content, /^[ \t]*using\s+([^;]+);/gm, (m) => m[1], 20),
        ...matchAll(content, /^[ \t]*require\s+['"]([^'"]+)['"]/gm, (m) => m[1], 20),
      ], 30);
      const types = matchAll(content, /^[ \t]*(?:export\s+)?(?:public\s+)?(?:abstract\s+|final\s+|sealed\s+)?(class|interface|enum|record|struct)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 20);
      const functions = matchAll(content, /^[ \t]*(?:export\s+)?(?:async\s+)?(?:function|def|fn)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[1], parameters: String(m[2] || '').trim() }), 40);
      return { path: filePath, language, imports, types, functions };
    }

    function summarizeImplementationFile(file) {
      const filePath = String(file?.path || '').trim();
      const content = String(file?.content || '');
      const language = detectLanguage(filePath);

      let summary;
      if (language === 'java' || language === 'kotlin') {
        summary = summarizeJava(filePath, content);
      } else if (language === 'python') {
        summary = summarizePython(filePath, content);
      } else if (language === 'typescript' || language === 'tsx' || language === 'javascript' || language === 'jsx') {
        summary = summarizeTsLike(filePath, content, language);
      } else if (language === 'csharp') {
        summary = summarizeCSharp(filePath, content);
      } else if (language === 'go') {
        summary = summarizeGo(filePath, content);
      } else {
        summary = summarizeGeneric(filePath, content, language);
      }

      summary.lineCount = content ? content.replace(/\r\n/g, '\n').split('\n').length : 0;
      return summary;
    }

    return $input.all().map((item) => {
      const json = item.json || {};
      const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];
      const generatedFilesThisIteration = Array.isArray(json.generatedFilesThisIteration) ? json.generatedFilesThisIteration : [];
      const generatedPaths = new Set(generatedFilesThisIteration.map((file) => String(file.path || '').trim()).filter(Boolean));

      const generatedNoFilesThisIteration = generatedFilesThisIteration.length === 0;

      const nextRemainingFiles = remainingFiles.filter((file) => !generatedPaths.has(String(file.path || '').trim()));
      const previousGeneratedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
      const previousGeneratedFilePaths = Array.isArray(json.generatedFilePaths) ? json.generatedFilePaths : [];
      const batchSize = Math.max(1, Number(json.batchSize || 15));

      const mergedGeneratedFiles = [
        ...previousGeneratedFiles,
        ...generatedFilesThisIteration,
      ];
      const mergedGeneratedFilePaths = [
        ...previousGeneratedFilePaths,
        ...generatedFilesThisIteration.map((file) => file.path),
      ];

      const generatedImplementationFiles = mergedGeneratedFiles.filter((file) => isImplementationFile(file.path));
      const generatedImplementationIndex = generatedImplementationFiles.map(summarizeImplementationFile);
      const generatedNonImplementationPaths = mergedGeneratedFiles
        .filter((file) => !isImplementationFile(file.path))
        .map((file) => String(file.path || '').trim())
        .filter(Boolean);
      const recentImplementationSummaries = generatedFilesThisIteration
        .filter((file) => isImplementationFile(file.path))
        .map(summarizeImplementationFile);

      const nextCurrentBatchFiles = nextRemainingFiles.slice(0, batchSize);

      return {
        json: {
          ...json,
          generatedFiles: mergedGeneratedFiles,
          generatedFilePaths: mergedGeneratedFilePaths,
          generatedImplementationIndex,
          generatedCodeIndex: generatedImplementationIndex,
          generatedNonImplementationPaths,
          recentImplementationSummaries,
          lastIterationFiles: generatedFilesThisIteration,
          generatedNoFilesThisIteration,
          generatedFileCountTotal: mergedGeneratedFiles.length,
          remainingFiles: nextRemainingFiles,
          remainingFileCount: nextRemainingFiles.length,
          batchSize,
          currentBatchFiles: nextCurrentBatchFiles,
          currentBatchFileCount: nextCurrentBatchFiles.length,
          hasRemainingFiles: nextRemainingFiles.length > 0 ? 'yes' : 'no',
          iteration: Number(json.iteration || 1) + (nextRemainingFiles.length > 0 ? 1 : 0),
        },
        binary: item.binary ?? {},
      };
    });
  }
return beUpdateGenerationState();

function beAssembleBackendZipInputs() {
    function getExtension(filePath) {
      const fileName = String(filePath || '').split('/').pop() || '';
      if (fileName === 'pom.xml') return 'xml';
      if (fileName === '.gitignore') return 'gitignore';
      const match = fileName.match(/\.([A-Za-z0-9]+)$/);
      return match ? match[1].toLowerCase() : 'txt';
    }

    function getMimeType(filePath) {
      const ext = getExtension(filePath);
      const mimeByExtension = {
        java: 'text/x-java-source',
        xml: 'application/xml',
        yaml: 'text/yaml',
        yml: 'text/yaml',
        json: 'application/json',
        properties: 'text/plain',
        md: 'text/markdown',
        txt: 'text/plain',
        sql: 'application/sql',
        csv: 'text/csv',
        gitignore: 'text/plain',
      };
      return mimeByExtension[ext] || 'text/plain';
    }

    function isIntentionallyEmptyFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('/.gitkeep') || lower.endsWith('/.keep') || lower.endsWith('/.placeholder');
    }

    function normalizeContent(contentValue) {
      if (typeof contentValue === 'string') {
        return contentValue;
      }
      if (contentValue === null || contentValue === undefined) {
        return '';
      }
      if (typeof contentValue === 'object') {
        return JSON.stringify(contentValue, null, 2);
      }
      return String(contentValue);
    }

    const item = $input.first();
    if (!item) {
      throw new Error('No tests generation state available for ZIP assembly.');
    }

    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];

    if (remainingFiles.length > 0) {
      throw new Error('Cannot assemble tests ZIP while files are still remaining.');
    }
    if (!generatedFiles.length) {
      throw new Error('No generated tests files available to assemble ZIP.');
    }

    const binary = {};
    const manifest = [];

    generatedFiles.forEach((file, index) => {
      const filePath = String(file?.path || '').trim();
      const content = normalizeContent(file?.content);
      if (!filePath.startsWith('tests/')) {
        throw new Error(`Generated tests file path must start with "tests/": ${filePath || '<empty>'}`);
      }
      if (!content.trim() && !isIntentionallyEmptyFile(filePath)) {
        throw new Error(`Generated tests file content is empty for: ${filePath}`);
      }

      const key = `file_${index}`;
      binary[key] = {
        data: Buffer.from(content, 'utf8').toString('base64'),
        mimeType: getMimeType(filePath),
        fileExtension: getExtension(filePath),
        fileName: filePath,
      };

      manifest.push({ path: filePath });
    });

    return [{
      json: {
        testsRoot: 'tests',
        fileCount: manifest.length,
        files: manifest,
        zipBinaryFields: Object.keys(binary).join(','),
      },
      binary,
    }];
  }
return beAssembleBackendZipInputs();

